import React from 'react';
import RepetitionExercise from './RepetitionExercise';
import DurationExercise from './DurationExercise';

function ExerciseScreen({ exercise, type }) {
  let component;

  switch (type) {
    case 'Repetition':
      component = <RepetitionExercise exercise={exercise} />;
      break;
    case 'Duration':
      component = <DurationExercise exercise={exercise} />;
      break;
    default:
      component = null;
  }

  return (
    <div>
      {component}
    </div>
  );
}

export default ExerciseScreen;
